import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Encoding user input using Apache Commons Text library
        String encodedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Displaying the properly encoded user input on a web page
        String output = "<div>" + encodedInput + "</div";

        System.out.println(output);
    }
}

